import { Song, Album, Artist, Playlist } from '../types';

const BASE_URL = 'https://yt-music-backend-qww6.onrender.com';

// --- OFFLINE STORAGE (IndexedDB) ---
const DB_NAME = 'vibestream_offline_db';
const STORE_NAME = 'songs';
const DB_VERSION = 1;

export const OfflineStorage = {
  openDB: (): Promise<IDBDatabase> => {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(DB_NAME, DB_VERSION);
      request.onerror = () => reject(request.error);
      request.onsuccess = () => resolve(request.result);
      request.onupgradeneeded = (e) => {
        const db = (e.target as IDBOpenDBRequest).result;
        if (!db.objectStoreNames.contains(STORE_NAME)) {
          db.createObjectStore(STORE_NAME); // Key is song ID
        }
      };
    });
  },

  saveSong: async (id: string, blob: Blob): Promise<void> => {
    const db = await OfflineStorage.openDB();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, 'readwrite');
      const store = tx.objectStore(STORE_NAME);
      const request = store.put(blob, id);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  },

  getSong: async (id: string): Promise<Blob | null> => {
    const db = await OfflineStorage.openDB();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, 'readonly');
      const store = tx.objectStore(STORE_NAME);
      const request = store.get(id);
      request.onsuccess = () => resolve(request.result || null);
      request.onerror = () => reject(request.error);
    });
  },

  removeSong: async (id: string): Promise<void> => {
    const db = await OfflineStorage.openDB();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, 'readwrite');
      const store = tx.objectStore(STORE_NAME);
      const request = store.delete(id);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  }
};

// Helper to safely get the high-quality image
export const getImageUrl = (images: { url: string }[]) => {
  if (!images || images.length === 0) return 'https://picsum.photos/500/500';
  // Try to find high quality 
  const high = images.find(i => i.url.includes('500x500') || i.url.includes('sddefault') || i.url.includes('hqdefault'));
  if (high) return high.url;
  return images[images.length - 1]?.url;
};

// Helper to get audio URL based on quality preference
export const getAudioUrl = (downloadUrls: { url: string, quality: string }[], preference: 'low' | 'normal' | 'high' = 'high') => {
  if (!downloadUrls || downloadUrls.length === 0) return '';
  // Return last available (best) if existing logic is used, but mostly we use getStreamUrl now
  return downloadUrls[downloadUrls.length - 1]?.url || '';
};

// Download Helper with Progress AND Offline Caching
export const downloadSongWithProgress = (songId: string, url: string, filename: string, onProgress: (percent: number) => void): Promise<void> => {
    return new Promise((resolve, reject) => {
        const xhr = new XMLHttpRequest();
        xhr.open('GET', url, true);
        xhr.responseType = 'blob';

        xhr.onload = async () => {
             if (xhr.status === 200) {
                 const blob = xhr.response;

                 // 1. Save to Offline Storage
                 try {
                     await OfflineStorage.saveSong(songId, blob);
                 } catch (e) {
                     console.error("Failed to cache audio offline", e);
                 }

                 // 2. Trigger Browser Download (Optional: Keep user happy with a file)
                 const blobUrl = window.URL.createObjectURL(blob);
                 const link = document.createElement('a');
                 link.href = blobUrl;
                 link.download = filename;
                 document.body.appendChild(link);
                 link.click();
                 document.body.removeChild(link);
                 window.URL.revokeObjectURL(blobUrl);

                 resolve();
             } else {
                 reject(new Error(`Download failed with status ${xhr.status}`));
             }
        };

        xhr.onerror = () => reject(new Error('Network Error during download'));

        xhr.onprogress = (e) => {
            if (e.lengthComputable) {
                const percent = (e.loaded / e.total) * 100;
                onProgress(percent);
            }
        };

        xhr.send();
    });
};

// Get Offline Blob URL
export const getOfflineAudioUrl = async (songId: string): Promise<string | null> => {
    try {
        const blob = await OfflineStorage.getSong(songId);
        if (blob) {
            return URL.createObjectURL(blob);
        }
        return null;
    } catch (e) {
        console.error("Error retrieving offline song", e);
        return null;
    }
};

export const downloadSong = async (song: Song) => {
    // This is the quick download fallback
    const url = await api.getStreamUrl(song.id);
    if (!url) return;
    const filename = `${song.name} - ${song.artists.primary[0]?.name || 'Artist'}.mp3`;
    await downloadSongWithProgress(song.id, url, filename, () => {});
};

// Cloudinary Upload Helper
export const uploadToCloudinary = async (file: File): Promise<string> => {
  const cloudName = 'dj5hhott5'; 
  const uploadPreset = 'My smallest server';

  const formData = new FormData();
  formData.append('file', file);
  formData.append('upload_preset', uploadPreset);
  formData.append('cloud_name', cloudName);

  try {
    const response = await fetch(`https://api.cloudinary.com/v1_1/${cloudName}/image/upload`, {
      method: 'POST',
      body: formData,
    });

    if (!response.ok) {
      throw new Error('Image upload failed');
    }

    const data = await response.json();
    return data.secure_url;
  } catch (error) {
    console.error('Cloudinary upload error:', error);
    throw error;
  }
};

async function fetchJson<T>(endpoint: string): Promise<T> {
  const response = await fetch(`${BASE_URL}${endpoint}`);
  if (!response.ok) {
    throw new Error(`API Error: ${response.statusText}`);
  }
  const json = await response.json();
  return json;
}

// Data Mapping Helper
const mapToSong = (item: any): Song => {
    // Normalize image
    let images: {quality: string, url: string}[] = [];
    if (item.image) {
        if (Array.isArray(item.image)) images = item.image;
        else images = [{ quality: 'high', url: item.image }];
    } else if (item.thumbnail) {
        images = [{ quality: 'high', url: item.thumbnail }];
    } else {
        images = [{ quality: 'high', url: 'https://picsum.photos/500/500' }];
    }

    return {
        id: item.id || item.videoId,
        name: item.title || item.name,
        type: 'song',
        album: {
            id: item.album?.id || '',
            name: item.album?.name || item.album || 'Single',
            url: ''
        },
        year: item.year || '',
        duration: item.duration_seconds ? String(item.duration_seconds) : (item.duration || '0'),
        language: '',
        genre: '',
        image: images,
        artists: {
            primary: [{ 
                id: '', 
                name: item.subtitle || item.artist || (item.artists && item.artists[0]?.name) || 'Unknown', 
                role: '', 
                image: [] 
            }],
            featured: [],
            all: []
        },
        downloadUrl: [] // Fetched lazily via /play
    };
};

const mapToAlbum = (item: any): Album => ({
    id: item.browseId || item.id,
    name: item.title || item.name,
    type: 'album',
    description: item.description || '',
    year: item.year || '',
    language: '',
    image: item.image ? (Array.isArray(item.image) ? item.image : [{ quality: 'high', url: item.image }]) : [],
    artists: {
        primary: [{ id: '', name: item.artist || 'Unknown', role: '', image: [] }]
    },
    songs: item.tracks ? item.tracks.map(mapToSong) : []
});

const mapToArtist = (item: any): Artist => ({
    id: item.browseId || item.id,
    name: item.name,
    type: 'artist',
    image: item.image ? (Array.isArray(item.image) ? item.image : [{ quality: 'high', url: item.image }]) : []
});

export const api = {
  getStreamUrl: async (videoId: string): Promise<string> => {
      try {
          const data = await fetchJson<{ stream_url: string }>(`/play/${videoId}`);
          return data.stream_url;
      } catch (e) {
          console.error("Stream fetch error", e);
          return '';
      }
  },

  getHomeData: async (): Promise<{ top_songs: Song[], trending_albums: Album[] }> => {
      try {
          const data = await fetchJson<{ top_songs: any[], trending_albums: any[] }>('/home');
          return {
              top_songs: (data.top_songs || []).map(mapToSong),
              trending_albums: (data.trending_albums || []).map(mapToAlbum)
          };
      } catch (e) {
          console.error("Home data error", e);
          return { top_songs: [], trending_albums: [] };
      }
  },

  searchSongs: async (query: string): Promise<Song[]> => {
    try {
      const data = await fetchJson<any[]>(`/search?query=${encodeURIComponent(query)}&type=songs`);
      return data.map(mapToSong);
    } catch (e) {
      console.error("Search songs error", e);
      return [];
    }
  },

  searchAlbums: async (query: string): Promise<Album[]> => {
    try {
      const data = await fetchJson<any[]>(`/search?query=${encodeURIComponent(query)}&type=albums`);
      return data.map(mapToAlbum);
    } catch (e) {
      console.error("Search albums error", e);
      return [];
    }
  },

  searchArtists: async (query: string): Promise<Artist[]> => {
    try {
      const data = await fetchJson<any[]>(`/search?query=${encodeURIComponent(query)}&type=artists`);
      return data.map(mapToArtist);
    } catch (e) {
      console.error("Search artists error", e);
      return [];
    }
  },

  getAlbumDetails: async (id: string): Promise<Album | null> => {
    try {
      const data = await fetchJson<any>(`/album/${id}`);
      return mapToAlbum(data);
    } catch (e) {
      console.error("Get album details error", e);
      return null;
    }
  },

  getPlaylistDetails: async (id: string): Promise<Playlist | null> => {
     try {
         const data = await fetchJson<any>(`/playlist/${id}`);
         return {
             id: data.id,
             title: data.title,
             subtitle: data.author,
             type: 'playlist',
             image: [],
             // We can augment this in usage if needed
         }
     } catch (e) { return null; }
  },

  getArtistDetails: async (id: string): Promise<any> => {
      try {
          const data = await fetchJson<any>(`/artist/${id}`);
          return {
              ...mapToArtist(data),
              top_songs: (data.top_songs || []).map(mapToSong)
          };
      } catch (e) { return null; }
  }
};

import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, MoreHorizontal, Download, ListMusic, Heart, Loader2, Shuffle, Repeat, PlusCircle, CheckCircle2, Disc, User, Share2, ListPlus, Radio, Mic2, Moon, Info, BellRing } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { api, getImageUrl, getAudioUrl, getOfflineAudioUrl } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';
import { Song } from '../types';
import { useNavigate } from 'react-router-dom';

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    setIsPlaying, 
    setIsBuffering,
    nextSong, 
    prevSong,
    likedSongs,
    toggleLike,
    isShuffling,
    streamingQuality,
    isOfflineMode,
    downloadedSongIds,
    addToQueue,
    startDownload
  } = usePlayerStore();

  const navigate = useNavigate();
  const audioRef = useRef<HTMLAudioElement>(null);

  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [dominantColor, setDominantColor] = useState<string>('#121212');
  const [isDragging, setIsDragging] = useState(false);

  const [isMoreMenuOpen, setIsMoreMenuOpen] = useState(false);
  const [isDownloadExpanded, setIsDownloadExpanded] = useState(false);

  // New States for enhanced features
  const [sleepTimerId, setSleepTimerId] = useState<number | null>(null);

  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;
  const isDownloaded = currentSong ? downloadedSongIds.includes(currentSong.id) : false;

  // Extract color from image
  useEffect(() => {
    if (!currentSong) return;
    const imgUrl = getImageUrl(currentSong.image);
    const img = new Image();
    img.crossOrigin = "Anonymous";
    img.src = imgUrl;

    img.onload = () => {
      try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        canvas.width = 1; 
        canvas.height = 1;
        ctx.drawImage(img, 0, 0, 1, 1);
        const [r, g, b] = ctx.getImageData(0, 0, 1, 1).data;
        setDominantColor(`rgb(${Math.max(20, r - 30)},${Math.max(20, g - 30)},${Math.max(20, b - 30)})`);
      } catch (e) {
        setDominantColor('#181818'); 
      }
    };
    img.onerror = () => setDominantColor('#181818');
  }, [currentSong?.id]);

  // MEDIA SESSION API INTEGRATION (Notification Poster)
  useEffect(() => {
    if (!currentSong || !('mediaSession' in navigator)) return;

    const artistName = currentSong.artists?.primary?.[0]?.name || "Unknown";
    // Get the high-quality image for the notification poster
    const hqImage = getImageUrl(currentSong.image);

    navigator.mediaSession.metadata = new MediaMetadata({
      title: currentSong.name,
      artist: artistName,
      album: currentSong.album?.name || "Single",
      artwork: [
          { src: hqImage, sizes: '96x96', type: 'image/jpeg' },
          { src: hqImage, sizes: '128x128', type: 'image/jpeg' },
          { src: hqImage, sizes: '192x192', type: 'image/jpeg' },
          { src: hqImage, sizes: '256x256', type: 'image/jpeg' },
          { src: hqImage, sizes: '384x384', type: 'image/jpeg' },
          { src: hqImage, sizes: '512x512', type: 'image/jpeg' },
      ]
    });

    navigator.mediaSession.setActionHandler('play', () => setIsPlaying(true));
    navigator.mediaSession.setActionHandler('pause', () => setIsPlaying(false));
    navigator.mediaSession.setActionHandler('previoustrack', prevSong);
    navigator.mediaSession.setActionHandler('nexttrack', nextSong);
    navigator.mediaSession.setActionHandler('seekto', (details) => {
        if (audioRef.current && details.seekTime !== undefined) {
            audioRef.current.currentTime = details.seekTime;
            setProgress(details.seekTime);
        }
    });
  }, [currentSong, setIsPlaying, prevSong, nextSong]);

  // Sync Playback State with Media Session
  useEffect(() => {
      if ('mediaSession' in navigator) {
          navigator.mediaSession.playbackState = isPlaying ? "playing" : "paused";
      }
  }, [isPlaying]);

  // Audio Source Logic
  useEffect(() => {
    if (!currentSong || !audioRef.current) return;

    const setAudioSource = async () => {
        let url = '';
        if (isOfflineMode || downloadedSongIds.includes(currentSong.id)) {
            const blobUrl = await getOfflineAudioUrl(currentSong.id);
            if (blobUrl) url = blobUrl;
            else if (isOfflineMode) { setIsPlaying(false); return; }
        }

        if (!url && !isOfflineMode) {
             // 1. Try pre-existing download URLs
             url = getAudioUrl(currentSong.downloadUrl, streamingQuality);
             // 2. If no URLs, fetch from Hybrid API
             if (!url) {
                 url = await api.getStreamUrl(currentSong.id);
             }
        }

        if (url && audioRef.current && audioRef.current.src !== url) {
            const wasPlaying = isPlaying;
            audioRef.current.src = url;
            audioRef.current.load();
            if (wasPlaying) {
                 audioRef.current.play().catch(() => setIsPlaying(false));
            }
        }
    };
    setAudioSource();
  }, [currentSong?.id, streamingQuality, isOfflineMode]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (isPlaying && audio.paused) audio.play().catch(e => console.warn("Play interrupted", e));
    else if (!isPlaying && !audio.paused) audio.pause();
  }, [isPlaying]);

  // Reset download expansion when menu closes or song changes
  useEffect(() => {
      if (!isMoreMenuOpen) setIsDownloadExpanded(false);
  }, [isMoreMenuOpen, currentSong?.id]);

  const handleTimeUpdate = () => {
    if (audioRef.current && !isDragging) {
      const currentTime = audioRef.current.currentTime;
      const duration = audioRef.current.duration || 0;

      setProgress(currentTime);
      setDuration(duration);

      if ('mediaSession' in navigator && duration > 0 && !isNaN(duration)) {
          try {
            navigator.mediaSession.setPositionState({
                duration: duration,
                playbackRate: audioRef.current.playbackRate,
                position: currentTime
            });
          } catch (e) {}
      }
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    setProgress(time);
    if (audioRef.current) audioRef.current.currentTime = time;
  };

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "-:--";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // --- ACTIONS FOR MORE MENU ---
  const handleAddToQueue = () => {
      if(currentSong) {
          addToQueue(currentSong);
          setIsMoreMenuOpen(false);
      }
  };

  const handleShare = async () => {
      if(!currentSong) return;
      const shareData = {
          title: currentSong.name,
          text: `Listen to ${currentSong.name} by ${currentSong.artists.primary[0].name}`,
          url: window.location.href
      };

      if (navigator.share) {
          try {
              await navigator.share(shareData);
          } catch(e) { console.log(e); }
      } else {
          navigator.clipboard.writeText(shareData.url);
      }
      setIsMoreMenuOpen(false);
  };

  const handleSleepTimer = () => {
      if (sleepTimerId) {
          clearTimeout(sleepTimerId);
          setSleepTimerId(null);
      } else {
          // Set for 30 mins
          const id = window.setTimeout(() => {
              setIsPlaying(false);
              setSleepTimerId(null);
          }, 30 * 60 * 1000); 
          setSleepTimerId(id);
      }
      setIsMoreMenuOpen(false);
  };

  const handleGoToRadio = async () => {
      if(!currentSong) return;
      setIsMoreMenuOpen(false);

      try {
         // Fetch recommendations (mocked by searching artist)
         const query = currentSong.artists.primary[0]?.name || currentSong.name;
         const songs = await api.searchSongs(query);
         const newSongs = songs.filter(s => s.id !== currentSong.id);

         if (newSongs.length > 0) {
             // Add first 10 to queue
             newSongs.slice(0, 10).forEach(s => addToQueue(s));
         } 
      } catch(e) {
          console.error("Radio failed", e);
      }
  };

  const handleDownloadSelect = (url: string, quality: string) => {
      if(!currentSong) return;
      const filename = `${currentSong.name} (${quality}) - ${currentSong.artists.primary[0]?.name || 'Artist'}.mp3`;
      startDownload(currentSong, url, filename);
      setIsMoreMenuOpen(false);
      setIsDownloadExpanded(false);
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;
    const touchEndX = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;
    const diffX = touchStart.x - touchEndX;
    const diffY = touchStart.y - touchEndY;

    if (Math.abs(diffX) > 50 && Math.abs(diffX) > Math.abs(diffY)) {
      if (diffX > 0) nextSong();
      else prevSong();
    }
    if (diffY < -80 && Math.abs(diffY) > Math.abs(diffX) && !isMoreMenuOpen) {
        setFullScreen(false);
    }
    setTouchStart(null);
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || "Unknown";

  return (
    <>
        <audio 
            ref={audioRef}
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            onEnded={nextSong}
            onWaiting={() => setIsBuffering(true)}
            onPlaying={() => setIsBuffering(false)}
            onCanPlay={() => setIsBuffering(false)}
            onPause={() => {
                if (isPlaying && !isBuffering && audioRef.current?.paused) setIsPlaying(false);
            }}
            onPlay={() => !isPlaying && setIsPlaying(true)}
        />

        <AnimatePresence mode="wait">
            {isFullScreen ? (
                <motion.div 
                    key="full-player"
                    initial={{ y: "100%" }}
                    animate={{ y: 0 }}
                    exit={{ y: "100%" }}
                    transition={{ type: "spring", damping: 30, stiffness: 300, mass: 0.8 }}
                    className="fixed inset-0 z-[200] flex flex-col bg-[#121212] isolate overflow-hidden"
                    onClick={(e) => e.stopPropagation()}
                    onTouchStart={handleTouchStart}
                    onTouchEnd={handleTouchEnd}
                >
                    {/* Background */}
                    <div 
                        className="absolute inset-0 z-[-1]"
                        style={{ 
                            background: `linear-gradient(to bottom, ${dominantColor}, #121212)`,
                        }}
                    />

                    {/* FULL PLAYER CONTENT */}
                    <div className="relative z-10 flex flex-col h-full px-6 pt-safe-top pb-safe-bottom">

                        {/* Header */}
                        <div className="flex items-center justify-between h-16 shrink-0 mt-2">
                            <button onClick={() => setFullScreen(false)} className="p-2 -ml-2 rounded-full hover:bg-white/10 shrink-0">
                                <ChevronDown size={28} className="text-white" />
                            </button>
                            <span className="text-[11px] font-bold tracking-[0.15em] uppercase text-white/70">
                                Now Playing
                            </span>
                            <button onClick={() => setIsMoreMenuOpen(true)} className="p-2 -mr-2 rounded-full hover:bg-white/10 shrink-0">
                                <MoreHorizontal size={24} className="text-white" />
                            </button>
                        </div>

                        {/* Main Artwork Area */}
                        <div className="flex-1 flex flex-col justify-center min-h-0 relative my-4">
                            <div className="relative w-full aspect-square max-w-[340px] mx-auto shadow-2xl rounded-xl overflow-hidden">
                                <img 
                                    src={imageUrl} 
                                    alt="Cover"
                                    className="w-full h-full object-cover"
                                />
                            </div>
                        </div>

                        {/* Info & Controls */}
                        <div className="flex flex-col gap-6 mb-10">
                            <div className="flex items-center justify-between">
                                <div className="flex flex-col overflow-hidden mr-4 min-w-0">
                                    <h2 className="text-2xl font-bold text-white truncate">
                                        {currentSong.name}
                                    </h2>
                                    <p className="text-lg text-white/70 truncate">
                                        {primaryArtistName}
                                    </p>
                                </div>
                                <button onClick={() => toggleLike(currentSong)} className="shrink-0">
                                    {isLiked ? <CheckCircle2 size={28} className="text-[#1DB954] fill-black" /> : <PlusCircle size={28} className="text-white/70" />}
                                </button>
                            </div>

                            {/* Scrubber - Improved Hit Area */}
                            <div className="flex flex-col gap-2 pt-2">
                                {/* Container with larger height for touch target */}
                                <div className="relative h-6 w-full flex items-center group cursor-pointer">

                                     {/* Background Track */}
                                     <div className="absolute left-0 right-0 h-1.5 bg-white/20 rounded-full overflow-hidden">
                                         {/* Progress Fill */}
                                         <div 
                                            className="h-full bg-white rounded-full transition-all duration-75 ease-out" 
                                            style={{ width: `${(progress / (duration || 1)) * 100}%` }}
                                         />
                                     </div>

                                     {/* Thumb (Dot) - Positioned based on progress */}
                                     <div 
                                        className="absolute h-3.5 w-3.5 bg-white rounded-full shadow-md scale-100 transition-transform active:scale-125 z-10 pointer-events-none"
                                        style={{ left: `calc(${(progress / (duration || 1)) * 100}% - 7px)` }}
                                     />

                                     {/* Interaction Layer (Invisible Input) */}
                                     <input 
                                        type="range" 
                                        min="0" 
                                        max={duration || 100} 
                                        step="any"
                                        value={progress}
                                        onChange={handleSeek}
                                        onMouseDown={() => setIsDragging(true)}
                                        onTouchStart={() => setIsDragging(true)}
                                        onMouseUp={() => setIsDragging(false)}
                                        onTouchEnd={() => setIsDragging(false)}
                                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-20"
                                    />
                                </div>
                                <div className="flex justify-between text-[11px] text-white/50 font-mono font-medium -mt-1">
                                    <span>{formatTime(progress)}</span>
                                    <span>{formatTime(duration)}</span>
                                </div>
                            </div>

                            {/* Controls */}
                            <div className="flex items-center justify-between px-2">
                                <button className={`shrink-0 ${isShuffling ? 'text-[#1DB954]' : 'text-white/40'}`}><Shuffle size={20} /></button>
                                <button onClick={prevSong} className="shrink-0"><SkipBack size={32} className="text-white" fill="white" /></button>
                                <button 
                                    onClick={togglePlay}
                                    className="w-16 h-16 bg-white rounded-full flex items-center justify-center hover:scale-105 active:scale-95 transition-transform shrink-0"
                                >
                                    {isBuffering ? <Loader2 size={32} className="animate-spin text-black" /> : isPlaying ? <Pause size={32} fill="black" className="text-black" /> : <Play size={32} fill="black" className="ml-1 text-black" />}
                                </button>
                                <button onClick={nextSong} className="shrink-0"><SkipForward size={32} className="text-white" fill="white" /></button>
                                <button className="text-white/40 shrink-0"><Repeat size={20} /></button>
                            </div>

                            {/* Bottom Row */}
                            <div className="flex items-center justify-between px-4">
                                <button className="text-white/50 shrink-0 hover:text-white transition-colors p-2">
                                    <Mic2 size={22} />
                                </button>
                                <button className="text-white/50 shrink-0 hover:text-white transition-colors p-2"><ListMusic size={22} /></button>
                            </div>
                        </div>
                    </div>

                    {/* More Menu (Enhanced) */}
                    <AnimatePresence>
                        {isMoreMenuOpen && (
                            <motion.div 
                                initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                                className="absolute inset-0 z-[250] bg-black/60 backdrop-blur-sm flex flex-col justify-end"
                                onClick={() => setIsMoreMenuOpen(false)}
                            >
                                <motion.div 
                                    initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
                                    transition={{ type: "tween", ease: "circOut", duration: 0.3 }}
                                    drag="y"
                                    dragConstraints={{ top: 0 }}
                                    dragElastic={{ top: 0, bottom: 0.2 }}
                                    onDragEnd={(_, info) => {
                                        if (info.offset.y > 100 || info.velocity.y > 100) {
                                            setIsMoreMenuOpen(false);
                                        }
                                    }}
                                    className="bg-[#242424] rounded-t-2xl flex flex-col max-h-[85vh] overflow-y-auto pb-6"
                                    onClick={e => e.stopPropagation()}
                                >
                                    {/* Drag Handle */}
                                    <div className="w-full flex justify-center pt-4 pb-2">
                                        <div className="w-10 h-1 bg-white/20 rounded-full"></div>
                                    </div>

                                    {/* Song Context Info */}
                                    <div className="flex items-center gap-3 px-6 pb-4">
                                        <img src={getImageUrl(currentSong.image)} className="w-12 h-12 rounded-md object-cover shadow-lg" alt="" />
                                        <div>
                                            <div className="font-bold text-white text-[15px]">{currentSong.name}</div>
                                            <div className="text-sm text-white/60">{primaryArtistName}</div>
                                        </div>
                                    </div>

                                    {/* Inline Accordion Download UI */}
                                    <div className="px-6 py-2">
                                        <div className={`rounded-xl transition-all border overflow-hidden ${isDownloadExpanded ? 'bg-[#2A2A2A] border-white/10' : 'bg-[#333] border-white/5'}`}>
                                            <button 
                                                onClick={async () => { 
                                                    if(isDownloaded) return; 
                                                    // If no pre-defined URLs, assume stream download
                                                    if (!currentSong.downloadUrl || currentSong.downloadUrl.length === 0) {
                                                        const url = await api.getStreamUrl(currentSong.id);
                                                        if(url) {
                                                            startDownload(currentSong, url, `${currentSong.name}.mp3`);
                                                            setIsMoreMenuOpen(false);
                                                        }
                                                    } else {
                                                        setIsDownloadExpanded(!isDownloadExpanded);
                                                    }
                                                }} 
                                                className={`w-full flex items-center justify-between p-4 ${isDownloaded ? 'cursor-default' : 'cursor-pointer'}`}
                                            >
                                                <div className="flex items-center gap-3">
                                                      <div className={`p-2 rounded-full ${isDownloaded ? 'bg-[#1DB954]/20 text-[#1DB954]' : 'bg-white/10 text-white'}`}>
                                                      <Download size={20} />
                                                      </div>
                                                      <div className="flex flex-col items-start">
                                                          <span className={`text-sm font-bold ${isDownloaded ? 'text-[#1DB954]' : 'text-white'}`}>
                                                              {isDownloaded ? 'Downloaded' : 'Download'}
                                                          </span>
                                                          <span className="text-[10px] text-white/50 font-medium">
                                                          {isDownloaded ? 'Available offline' : (currentSong.downloadUrl?.length > 0 ? (isDownloadExpanded ? 'Select Quality' : 'Tap to choose quality') : 'Tap to download')}
                                                          </span>
                                                      </div>
                                                </div>
                                                {isDownloaded ? <CheckCircle2 size={20} className="text-[#1DB954]" /> : (
                                                    (currentSong.downloadUrl?.length > 0) && <ChevronDown size={20} className={`text-white/50 transition-transform ${isDownloadExpanded ? 'rotate-180' : ''}`} />
                                                )}
                                            </button>

                                            {/* Expanded Options */}
                                            <AnimatePresence>
                                                {isDownloadExpanded && !isDownloaded && currentSong.downloadUrl?.length > 0 && (
                                                    <motion.div 
                                                        initial={{ height: 0, opacity: 0 }}
                                                        animate={{ height: 'auto', opacity: 1 }}
                                                        exit={{ height: 0, opacity: 0 }}
                                                        className="border-t border-white/5 bg-[#252525]"
                                                    >
                                                        {currentSong.downloadUrl.slice().sort((a,b) => parseInt(b.quality.replace(/\D/g, '')) - parseInt(a.quality.replace(/\D/g, ''))).map((opt) => (
                                                            <button
                                                                key={opt.quality}
                                                                onClick={() => handleDownloadSelect(opt.url, opt.quality)}
                                                                className="w-full flex items-center justify-between px-4 py-3 hover:bg-white/5 transition-colors group border-b border-white/5 last:border-0"
                                                            >
                                                                <div className="flex flex-col items-start">
                                                                    <span className="text-white font-medium text-sm">{opt.quality}</span>
                                                                    <span className="text-[10px] text-white/40 group-hover:text-white/60">
                                                                        {opt.quality.includes('320') ? 'Best Quality (~8MB)' : opt.quality.includes('160') ? 'Good Balance (~4MB)' : 'Data Saver'}
                                                                    </span>
                                                                </div>
                                                                <Download size={16} className="text-white/20 group-hover:text-white" />
                                                            </button>
                                                        ))}
                                                    </motion.div>
                                                )}
                                            </AnimatePresence>
                                        </div>
                                    </div>

                                    {/* Menu Actions List */}
                                    <div className="flex flex-col py-2">

                                        <button onClick={() => { toggleLike(currentSong); setIsMoreMenuOpen(false); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Heart size={24} className={isLiked ? "text-[#1DB954] fill-[#1DB954]" : "text-white/80"} />
                                            <span className="text-white font-medium">{isLiked ? 'Liked' : 'Like'}</span>
                                        </button>

                                        <button onClick={handleAddToQueue} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <ListPlus size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Add to queue</span>
                                        </button>

                                        <button onClick={handleShare} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Share2 size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Share</span>
                                        </button>

                                        <button onClick={() => { setIsMoreMenuOpen(false); navigate(`/artist/${currentSong.artists.primary[0].id}`, { state: { artist: currentSong.artists.primary[0] } }); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <User size={24} className="text-white/80" />
                                            <span className="text-white font-medium">View Artist</span>
                                        </button>

                                        <button onClick={() => { setIsMoreMenuOpen(false); navigate(`/album/${currentSong.album.id}`); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Disc size={24} className="text-white/80" />
                                            <span className="text-white font-medium">View Album</span>
                                        </button>

                                        <button onClick={handleSleepTimer} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Moon size={24} className={sleepTimerId ? "text-[#1DB954]" : "text-white/80"} />
                                            <span className="text-white font-medium">{sleepTimerId ? 'Stop Sleep Timer' : 'Sleep Timer (30 mins)'}</span>
                                        </button>

                                        <button onClick={handleGoToRadio} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Radio size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Go to Song Radio</span>
                                        </button>

                                        <button className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Info size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Show credits</span>
                                        </button>

                                    </div>

                                </motion.div>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </motion.div>
            ) : (
                <motion.div 
                    key="mini-player"
                    initial={{ y: 50, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    exit={{ y: 50, opacity: 0 }}
                    transition={{ type: "spring", stiffness: 400, damping: 30 }}
                    className="fixed bottom-[68px] md:bottom-4 left-2 right-2 md:left-1/2 md:-translate-x-1/2 md:w-[450px] h-[56px] z-[150] cursor-pointer isolate"
                    onClick={() => setFullScreen(true)}
                >
                    {/* Background */}
                    <div 
                        className="absolute inset-0 z-[-1] rounded-lg shadow-xl overflow-hidden"
                        style={{ backgroundColor: dominantColor }}
                    >
                         <div className="absolute inset-0 bg-black/20" />
                    </div>

                    <div className="flex items-center h-full px-2 gap-3">
                        {/* Image */}
                        <div className="h-10 w-10 shrink-0 rounded-[4px] overflow-hidden shadow-sm">
                            <img src={imageUrl} alt="" className="w-full h-full object-cover" />
                        </div>

                        {/* Text Info */}
                        <div className="flex-1 flex flex-col justify-center min-w-0 pr-2">
                            <span className="text-white font-bold text-xs truncate">
                                {currentSong.name}
                            </span>
                            <span className="text-white/70 text-[10px] truncate">
                                {primaryArtistName}
                            </span>
                        </div>

                        {/* Controls */}
                        <div className="flex items-center gap-1.5 pr-1 shrink-0">
                            {/* Like Button */}
                            <button onClick={(e) => { e.stopPropagation(); toggleLike(currentSong); }} className="shrink-0 p-1.5">
                                <Heart size={20} fill={isLiked ? "#1DB954" : "none"} className={isLiked ? "text-[#1DB954]" : "text-white"} />
                            </button>

                            {/* Previous Button (Hidden on very small screens if needed, but fitting here) */}
                            <button onClick={(e) => { e.stopPropagation(); prevSong(); }} className="shrink-0 p-1.5 text-white/90 hover:text-white">
                                <SkipBack size={22} fill="white" />
                            </button>

                            {/* Play/Pause Button */}
                            <button onClick={(e) => { e.stopPropagation(); togglePlay(); }} className="shrink-0 p-1.5">
                                {isBuffering ? (
                                    <Loader2 size={24} className="animate-spin text-white" />
                                ) : isPlaying ? (
                                    <Pause size={24} fill="white" className="text-white" />
                                ) : (
                                    <Play size={24} fill="white" className="text-white" />
                                )}
                            </button>

                            {/* Next Button */}
                            <button onClick={(e) => { e.stopPropagation(); nextSong(); }} className="shrink-0 p-1.5 text-white/90 hover:text-white">
                                <SkipForward size={22} fill="white" />
                            </button>
                        </div>
                    </div>

                    {/* Progress Bar (Mini only) */}
                    <div className="absolute bottom-0 left-1 right-1 h-[2px] bg-white/20 rounded-full overflow-hidden">
                        <div className="h-full bg-white rounded-full" style={{ width: `${(progress / (duration || 1)) * 100}%` }}></div>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
    </>
  );
};

import React, { useEffect, useState } from 'react';
import { api, getImageUrl } from '../services/api';
import { Song, Album } from '../types';
import { usePlayerStore } from '../store/playerStore';
import { Bell, History, Settings, Play, UserCircle, WifiOff, Rocket } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { SongCard } from '../components/SongCard';
import { motion } from 'framer-motion';

// Animation Variants
const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.1,
      delayChildren: 0.1
    }
  }
};

const itemVariants = {
  hidden: { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0 }
};

// Skeleton Component
const SkeletonCard: React.FC<{ round?: boolean }> = ({ round = false }) => (
  <div className="bg-[#181818]/60 p-3 rounded-xl w-[160px] md:w-[180px] shrink-0 border border-white/5 animate-pulse">
    <div className={`w-full aspect-square mb-3 bg-white/10 ${round ? 'rounded-full' : 'rounded-lg'}`}></div>
    <div className="flex flex-col gap-2">
      <div className="h-4 bg-white/10 rounded w-3/4"></div>
      <div className="h-3 bg-white/5 rounded w-1/2"></div>
    </div>
  </div>
);

const SkeletonShortcut: React.FC = () => (
  <div className="glass-card flex items-center gap-0 h-[48px] overflow-hidden rounded-[4px] bg-[#2A2A2A] animate-pulse">
     <div className="h-[48px] w-[48px] bg-white/10 shrink-0"></div>
     <div className="flex-1 px-2">
         <div className="h-3 bg-white/10 rounded w-3/4"></div>
     </div>
  </div>
);

export const Home: React.FC = () => {
  const [daylist, setDaylist] = useState<Song[]>([]);
  const [trendingAlbums, setTrendingAlbums] = useState<Album[]>([]);
  const [recent, setRecent] = useState<(Song | Album)[]>([]); 
  const { history, playSong, currentUser, isOfflineMode, downloadedSongIds, likedSongs } = usePlayerStore();
  const navigate = useNavigate();
  const [isLoading, setIsLoading] = useState(true);
  const [isScrolled, setIsScrolled] = useState(false);

  useEffect(() => {
    // Only fetch if online
    if (isOfflineMode) {
        setIsLoading(false);
        // Load local content for offline view
        const offlineSongs = likedSongs.filter(s => downloadedSongIds.includes(s.id));
        setDaylist(offlineSongs);
        return;
    }

    const fetchData = async () => {
      setIsLoading(true);
      try {
        const homeData = await api.getHomeData();
        setDaylist(homeData.top_songs);
        setTrendingAlbums(homeData.trending_albums);
      } catch (e) {
        console.error(e);
      } finally {
        setIsLoading(false);
      }
    };
    fetchData();
  }, [isOfflineMode]);

  useEffect(() => {
    // Populate recent with history or default items
    if (history.length > 0) {
      setRecent(history.slice(0, 6));
    } else {
        // If history is empty, use trending albums as placeholders if available
        if (trendingAlbums.length > 0) {
            setRecent(trendingAlbums.slice(0, 6));
        }
    }
  }, [history, trendingAlbums, isOfflineMode]);

  // Scroll listener for header effect (Attached to main container)
  useEffect(() => {
    const main = document.querySelector('main');
    const handleScroll = () => {
        if (main) setIsScrolled(main.scrollTop > 10);
    };
    main?.addEventListener('scroll', handleScroll);
    return () => main?.removeEventListener('scroll', handleScroll);
  }, []);

  const ShortcutCard: React.FC<{ title: string, image?: string, specialType?: 'liked' | 'whyus', onClick?: () => void }> = ({ title, image, specialType, onClick }) => (
    <motion.div 
        whileHover={{ scale: 1.02, backgroundColor: '#3E3E3E' }}
        whileTap={{ scale: 0.98 }}
        onClick={onClick}
        className="glass-card flex items-center gap-0 cursor-pointer h-[48px] overflow-hidden group rounded-[4px] bg-[#2A2A2A] transition-colors"
    >
        {specialType === 'liked' ? (
            <div className="h-full w-[48px] bg-gradient-to-br from-[#450af5] to-[#c4efd9] flex items-center justify-center shrink-0 opacity-100">
                <svg role="img" height="18" width="18" aria-hidden="true" viewBox="0 0 24 24" fill="white"><path d="M15.724 4.22A4.313 4.313 0 0 0 12.192.814a4.269 4.269 0 0 0-3.622 1.13.837.837 0 0 1-1.14 0 4.272 4.272 0 0 0-6.21 5.855l5.916 7.05a1.128 1.128 0 0 0 1.727 0l5.916-7.05a4.228 4.228 0 0 0 .945-3.577z"></path></svg>
            </div>
        ) : specialType === 'whyus' ? (
            <div className="h-full w-[48px] bg-gradient-to-br from-[#1DB954] to-emerald-700 flex items-center justify-center shrink-0 opacity-100">
                <Rocket size={20} className="text-white" />
            </div>
        ) : (
            <img src={image} className="h-[48px] w-[48px] object-cover shrink-0 shadow-none" alt=""/>
        )}
        <div className="flex flex-1 items-center justify-between pr-2 pl-2 overflow-hidden">
             <span className={`font-bold text-[11px] md:text-[13px] leading-tight line-clamp-2 pr-1 ${specialType === 'whyus' ? 'text-[#1DB954]' : 'text-white'}`}>{title}</span>
        </div>
    </motion.div>
  );

  const SectionTitle = ({ title }: { title: string }) => (
      <h2 className="text-xl md:text-2xl font-bold mb-4 text-white px-4 hover:underline cursor-pointer tracking-tight">{title}</h2>
  );

  const handleProfileClick = () => {
    if (currentUser) {
        navigate('/profile');
    } else {
        navigate('/login');
    }
  };

  return (
    <motion.div 
      variants={containerVariants}
      initial="hidden"
      animate="visible"
      className={`flex flex-col gap-6 min-h-full pb-36 relative bg-black`}
    >

      {/* Top Header */}
      <div className={`px-4 flex items-center justify-start gap-3 sticky top-0 z-50 py-3 transition-colors duration-200 ${isScrolled ? 'bg-black/95 border-b border-[#282828] shadow-lg' : 'bg-black border-b border-transparent'}`}>
         {/* Profile Icon */}
         <motion.div 
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            onClick={handleProfileClick}
            className="w-8 h-8 rounded-full bg-gradient-to-tr from-[#1DB954] to-[#1ed760] flex items-center justify-center font-bold text-black text-sm shrink-0 cursor-pointer overflow-hidden shadow-md"
         >
             {currentUser && currentUser.image ? (
                 <img src={currentUser.image} alt="Profile" className="w-full h-full object-cover" />
             ) : (
                 <span className="font-bold">{currentUser ? currentUser.name.charAt(0).toUpperCase() : <UserCircle size={20} />}</span>
             )}
         </motion.div>

         {/* Filter Chips */}
         <div className="flex items-center gap-2 overflow-x-auto no-scrollbar mask-linear-fade">
             {!isOfflineMode && (
                <>
                    <motion.button whileTap={{ scale: 0.95 }} className="px-4 py-1.5 bg-[#1DB954] text-black rounded-full text-[13px] font-medium transition-transform shadow-sm whitespace-nowrap">All</motion.button>
                    <motion.button whileTap={{ scale: 0.95 }} className="px-4 py-1.5 bg-[#2A2A2A] text-white rounded-full text-[13px] font-medium whitespace-nowrap border border-transparent hover:bg-[#333]">Music</motion.button>
                </>
             )}
             {isOfflineMode && (
                 <motion.button className="px-4 py-1.5 bg-[#2A2A2A] text-white rounded-full text-[13px] font-medium flex items-center gap-2">
                     <WifiOff size={14} /> Offline Mode
                 </motion.button>
             )}
         </div>
      </div>

      {/* Grid Shortcuts */}
      <motion.div variants={itemVariants} className="px-4 mt-2">
          <h2 className="text-2xl font-bold text-white mb-4">{isOfflineMode ? "Your Downloads" : "Jump back in"}</h2>
          <div className="grid grid-cols-2 gap-2">
            <ShortcutCard title="Liked Songs" specialType="liked" onClick={() => navigate('/library')} />

            {/* NEW WHY US CARD */}
            <ShortcutCard title="Why Vibestream?" specialType="whyus" onClick={() => navigate('/why-us')} />

