import { Song, Album, Artist, Playlist } from '../types';

const SAAVN_API = 'https://musicapi-gray.vercel.app/api';
const YT_API = 'https://yt-music-backend-qww6.onrender.com';

// --- OFFLINE STORAGE (IndexedDB) ---
const DB_NAME = 'vibestream_offline_db';
const STORE_NAME = 'songs';
const DB_VERSION = 1;

export const OfflineStorage = {
  openDB: (): Promise<IDBDatabase> => {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(DB_NAME, DB_VERSION);
      request.onerror = () => reject(request.error);
      request.onsuccess = () => resolve(request.result);
      request.onupgradeneeded = (e) => {
        const db = (e.target as IDBOpenDBRequest).result;
        if (!db.objectStoreNames.contains(STORE_NAME)) {
          db.createObjectStore(STORE_NAME); // Key is song ID
        }
      };
    });
  },

  saveSong: async (id: string, blob: Blob): Promise<void> => {
    const db = await OfflineStorage.openDB();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, 'readwrite');
      const store = tx.objectStore(STORE_NAME);
      const request = store.put(blob, id);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  },

  getSong: async (id: string): Promise<Blob | null> => {
    const db = await OfflineStorage.openDB();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, 'readonly');
      const store = tx.objectStore(STORE_NAME);
      const request = store.get(id);
      request.onsuccess = () => resolve(request.result || null);
      request.onerror = () => reject(request.error);
    });
  },

  removeSong: async (id: string): Promise<void> => {
    const db = await OfflineStorage.openDB();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, 'readwrite');
      const store = tx.objectStore(STORE_NAME);
      const request = store.delete(id);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  }
};

// Helper to safely get the high-quality image
export const getImageUrl = (images: { url: string }[]) => {
  if (!images || images.length === 0) return 'https://picsum.photos/500/500';
  // Check for high quality specific URLs first
  const highQuality = images.find(i => i.url.includes('500x500') || i.url.includes('hqdefault'));
  if (highQuality) return highQuality.url;
  // Fallback to the last image (usually highest in array)
  return images[images.length - 1]?.url;
};

// Helper to get audio URL based on quality preference
export const getAudioUrl = (downloadUrls: { url: string, quality: string }[], preference: 'low' | 'normal' | 'high' = 'high') => {
  if (!downloadUrls || downloadUrls.length === 0) return '';

  // Sort from low to high quality based on bitrate number
  const sorted = [...downloadUrls].sort((a, b) => {
     const bitrateA = parseInt(a.quality.replace(/\D/g, '')) || 0;
     const bitrateB = parseInt(b.quality.replace(/\D/g, '')) || 0;
     return bitrateA - bitrateB;
  });

  if (sorted.length === 0) return '';

  if (preference === 'low') {
      return sorted[0].url;
  } else if (preference === 'normal') {
      const mid = Math.floor(sorted.length / 2);
      return sorted[mid].url;
  } else {
      return sorted[sorted.length - 1].url;
  }
};

// Download Helper with Progress AND Offline Caching
export const downloadSongWithProgress = (songId: string, url: string, filename: string, onProgress: (percent: number) => void): Promise<void> => {
    return new Promise((resolve, reject) => {
        const xhr = new XMLHttpRequest();
        xhr.open('GET', url, true);
        xhr.responseType = 'blob';

        xhr.onload = async () => {
             if (xhr.status === 200) {
                 const blob = xhr.response;
                 try {
                     await OfflineStorage.saveSong(songId, blob);
                 } catch (e) {
                     console.error("Failed to cache audio offline", e);
                 }

                 const blobUrl = window.URL.createObjectURL(blob);
                 const link = document.createElement('a');
                 link.href = blobUrl;
                 link.download = filename;
                 document.body.appendChild(link);
                 link.click();
                 document.body.removeChild(link);
                 window.URL.revokeObjectURL(blobUrl);

                 resolve();
             } else {
                 reject(new Error(`Download failed with status ${xhr.status}`));
             }
        };

        xhr.onerror = () => reject(new Error('Network Error during download'));

        xhr.onprogress = (e) => {
            if (e.lengthComputable) {
                const percent = (e.loaded / e.total) * 100;
                onProgress(percent);
            }
        };

        xhr.send();
    });
};

export const getOfflineAudioUrl = async (songId: string): Promise<string | null> => {
    try {
        const blob = await OfflineStorage.getSong(songId);
        if (blob) {
            return URL.createObjectURL(blob);
        }
        return null;
    } catch (e) {
        console.error("Error retrieving offline song", e);
        return null;
    }
};

export const downloadSong = async (song: Song) => {
    const url = getAudioUrl(song.downloadUrl, 'high');
    // If no downloadUrl, we might need to fetch stream URL first (handled in Player mostly, but here we fallback)
    if (!url) return; 
    const filename = `${song.name} - ${song.artists.primary[0]?.name || 'Artist'}.mp3`;
    await downloadSongWithProgress(song.id, url, filename, () => {});
};

export const uploadToCloudinary = async (file: File): Promise<string> => {
  const cloudName = 'dj5hhott5'; 
  const uploadPreset = 'My smallest server';
  const formData = new FormData();
  formData.append('file', file);
  formData.append('upload_preset', uploadPreset);
  formData.append('cloud_name', cloudName);

  try {
    const response = await fetch(`https://api.cloudinary.com/v1_1/${cloudName}/image/upload`, {
      method: 'POST',
      body: formData,
    });
    if (!response.ok) throw new Error('Image upload failed');
    const data = await response.json();
    return data.secure_url;
  } catch (error) {
    console.error('Cloudinary upload error:', error);
    throw error;
  }
};

// --- DATA MAPPING HELPERS ---

// Map YT Backend item to Song
const mapYtSong = (item: any): Song => ({
    id: item.id || item.videoId,
    name: item.title || item.name,
    type: 'song',
    year: '',
    duration: item.duration_seconds ? String(item.duration_seconds) : '',
    language: '',
    genre: '',
    image: item.image ? [{ quality: 'high', url: item.image }] : (item.thumbnail ? [{ quality: 'high', url: item.thumbnail }] : []),
    artists: {
        primary: [{ 
            id: '', 
            name: item.subtitle || item.artist || 'Unknown', 
            role: '', 
            image: [] 
        }],
        featured: [],
        all: []
    },
    album: { id: '', name: '', url: '' },
    downloadUrl: [] // Empty implies stream url needs to be fetched
});

// Map YT Backend item to Album
const mapYtAlbum = (item: any): Album => ({
    id: item.id || item.browseId,
    name: item.title || item.name,
    type: 'album',
    description: '',
    year: item.year || '',
    language: '',
    image: item.image ? [{ quality: 'high', url: item.image }] : [],
    artists: {
        primary: [{ id: '', name: item.subtitle || item.artist || 'Unknown', role: '', image: [] }]
    }
});

// Map YT Backend item to Artist
const mapYtArtist = (item: any): Artist => ({
    id: item.id || item.browseId,
    name: item.title || item.name,
    type: 'artist',
    image: item.image ? [{ quality: 'high', url: item.image }] : []
});


async function fetchJson<T>(url: string): Promise<T> {
  const response = await fetch(url);
  if (!response.ok) throw new Error(`API Error: ${response.statusText}`);
  return response.json();
}

export const api = {
  // New API Method to get stream URL
  getStreamUrl: async (videoId: string): Promise<string> => {
      try {
          const data = await fetchJson<{ stream_url: string }>(`${YT_API}/play/${videoId}`);
          return data.stream_url;
      } catch (e) {
          console.error("Failed to fetch stream url", e);
          return '';
      }
  },

  searchSongs: async (query: string): Promise<Song[]> => {
    try {
      const [saavnRes, ytRes] = await Promise.allSettled([
          fetchJson<{ data: { results: Song[] } }>(`${SAAVN_API}/search/songs?query=${encodeURIComponent(query)}`),
          fetchJson<any[]>(`${YT_API}/search?query=${encodeURIComponent(query)}&type=songs`)
      ]);

      let results: Song[] = [];

      // Process Saavn
      if (saavnRes.status === 'fulfilled' && saavnRes.value.data?.results) {
          results = [...results, ...saavnRes.value.data.results];
      }

      // Process YT
      if (ytRes.status === 'fulfilled' && Array.isArray(ytRes.value)) {
          const ytSongs = ytRes.value.map(mapYtSong);
          results = [...results, ...ytSongs];
      }

      return results;
    } catch (e) {
      console.error("Search songs error", e);
      return [];
    }
  },

  searchAlbums: async (query: string): Promise<Album[]> => {
    try {
      const [saavnRes, ytRes] = await Promise.allSettled([
          fetchJson<{ data: { results: Album[] } }>(`${SAAVN_API}/search/albums?query=${encodeURIComponent(query)}`),
          fetchJson<any[]>(`${YT_API}/search?query=${encodeURIComponent(query)}&type=albums`)
      ]);

      let results: Album[] = [];

      if (saavnRes.status === 'fulfilled' && saavnRes.value.data?.results) {
          results = [...results, ...saavnRes.value.data.results];
      }

      if (ytRes.status === 'fulfilled' && Array.isArray(ytRes.value)) {
          results = [...results, ...ytRes.value.map(mapYtAlbum)];
      }

      return results;
    } catch (e) {
      console.error("Search albums error", e);
      return [];
    }
  },

  searchArtists: async (query: string): Promise<Artist[]> => {
    try {
      const [saavnRes, ytRes] = await Promise.allSettled([
          fetchJson<{ data: { results: Artist[] } }>(`${SAAVN_API}/search/artists?query=${encodeURIComponent(query)}`),
          fetchJson<any[]>(`${YT_API}/search?query=${encodeURIComponent(query)}&type=artists`) // Note: YT endpoint might not differentiate artist type perfectly in general search, assuming type param works
      ]);

      let results: Artist[] = [];

      if (saavnRes.status === 'fulfilled' && saavnRes.value.data?.results) {
          results = [...results, ...saavnRes.value.data.results];
      }

      // If YT has artist search
      if (ytRes.status === 'fulfilled' && Array.isArray(ytRes.value)) {
           // Filter just in case
           results = [...results, ...ytRes.value.map(mapYtArtist)];
      }

      return results;
    } catch (e) {
      console.error("Search artists error", e);
      return [];
    }
  },

  getAlbumDetails: async (id: string): Promise<Album | null> => {
    try {
        // Try Saavn first (ID format usually purely numeric or specific hash)
        // If it fails or is a YT ID (often starts with MP...), try YT
        if (id.startsWith('MPRE') || id.length > 20) {
            const ytData = await fetchJson<any>(`${YT_API}/album/${id}`);
            if (ytData) {
                return {
                    ...mapYtAlbum(ytData),
                    songs: ytData.tracks ? ytData.tracks.map(mapYtSong) : []
                };
            }
        }

        const data = await fetchJson<{ data: Album }>(`${SAAVN_API}/albums?id=${id}`);
        return data.data || null;
    } catch (e) {
      console.error("Get album details error", e);
      return null;
    }
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Search as SearchIcon, ArrowLeft, X, Loader2, Play, CheckCircle2, PlusCircle, ArrowUpLeft, MoreVertical } from 'lucide-react';
import { api, getImageUrl } from '../services/api';
import { Song, Album, Artist } from '../types';
import { usePlayerStore } from '../store/playerStore';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';

const FILTER_CHIPS = ["Top", "Songs", "Albums", "Artists", "Playlists"];

const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.05
    }
  }
};

const itemVariants = {
  hidden: { opacity: 0, scale: 0.9 },
  visible: { opacity: 1, scale: 1 }
};

export const Search: React.FC = () => {
  const [query, setQuery] = useState('');
  const [activeFilter, setActiveFilter] = useState('Top');
  const [results, setResults] = useState<{ songs: Song[], albums: Album[], artists: Artist[] }>({ songs: [], albums: [], artists: [] });
  const [isLoading, setIsLoading] = useState(false);
  const [isFocused, setIsFocused] = useState(false);

  const { playSong, likedSongs, toggleLike } = usePlayerStore();
  const navigate = useNavigate();

  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    if (abortControllerRef.current) {
        abortControllerRef.current.abort();
    }

    if (!query.trim()) {
        setResults({ songs: [], albums: [], artists: [] });
        setIsLoading(false);
        return;
    }

    setIsLoading(true);

    const timer = setTimeout(async () => {
        abortControllerRef.current = new AbortController();
        try {
           const [songs, albums, artists] = await Promise.all([
              api.searchSongs(query),
              api.searchAlbums(query),
              api.searchArtists(query)
           ]);

           if (!abortControllerRef.current?.signal.aborted) {
               setResults({ songs, albums, artists });
           }
        } catch (e: any) {
            if (e.name !== 'AbortError') console.error(e);
        } finally {
            if (!abortControllerRef.current?.signal.aborted) setIsLoading(false);
        }
    }, 400);

    return () => clearTimeout(timer);
  }, [query]);

  const clearSearch = () => {
    setQuery('');
    setResults({ songs: [], albums: [], artists: [] });
    setIsLoading(false);
    setActiveFilter('Top');
  };

  const ResultSkeleton = () => (
      <div className="flex items-center gap-3 px-4 py-2.5 animate-pulse">
          <div className="w-12 h-12 bg-white/10 rounded-md shrink-0"></div>
          <div className="flex-1 space-y-2 py-1">
              <div className="h-4 bg-white/10 rounded w-1/3"></div>
              <div className="h-3 bg-white/5 rounded w-1/4"></div>
          </div>
      </div>
  );

  const renderSongsList = (songs: Song[], limit?: number) => {
      const list = limit ? songs.slice(0, limit) : songs;
      return list.map((song) => {
          const isLiked = likedSongs.some(s => s.id === song.id);
          const artistName = song.artists?.primary?.[0]?.name || "Unknown";
          return (
             <div 
                key={song.id} 
                className="flex items-center gap-3 px-4 py-2 hover:bg-[#1A1A1A] cursor-pointer group transition-colors" 
                onClick={() => playSong(song, songs)}
             >
                 <div className="w-12 h-12 shrink-0 relative">
                    <img src={getImageUrl(song.image)} className="w-full h-full rounded-[4px] object-cover" alt="" />
                 </div>
                 <div className="flex-1 min-w-0 flex flex-col justify-center gap-0.5">
                     <div className={`font-medium truncate text-[16px] text-white ${isLiked ? 'text-[#1DB954]' : ''}`}>{song.name}</div>
                     <div className="text-[#B3B3B3] text-sm truncate flex items-center gap-1">
                        {song.name.toLowerCase().includes('explicit') && (
                            <span className="bg-[#B3B3B3] text-black text-[9px] px-1 rounded-[2px] font-bold">E</span>
                        )}
                        <span>Song • {artistName}</span>
                     </div>
                 </div>

                 <div className="flex items-center gap-4">
                     <button 
                        className="text-[#B3B3B3] hover:text-white transition-transform active:scale-90" 
                        onClick={(e) => { e.stopPropagation(); toggleLike(song); }}
                     >
                        {isLiked ? (
                            <CheckCircle2 size={22} className="text-[#1DB954] fill-[#1DB954] text-black" />
                        ) : (
                            <PlusCircle size={22} />
                        )}
                     </button>
                     <button className="text-[#B3B3B3] hover:text-white" onClick={(e) => e.stopPropagation()}>
                         <MoreVertical size={20} />
                     </button>
                 </div>
             </div>
          );
      });
  };

  const renderGrid = (items: (Album | Artist)[], type: 'Album' | 'Artist') => (
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 px-4">
          {items.map((item) => (
              <div 
                key={item.id} 
                className="bg-[#181818] p-3 rounded-lg hover:bg-[#282828] transition-colors cursor-pointer group"
                onClick={() => type === 'Album' ? navigate(`/album/${item.id}`) : navigate(`/artist/${item.id}`, { state: { artist: item } })}
              >
                  <div className={`w-full aspect-square mb-3 shadow-lg overflow-hidden ${type === 'Artist' ? 'rounded-full' : 'rounded-md'}`}>
                      <img src={getImageUrl(item.image)} alt={item.name} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300" />
                  </div>
                  <h3 className="text-white font-bold truncate text-[15px] text-center">{item.name}</h3>
                  <p className="text-[#B3B3B3] text-xs text-center mt-1">{type}</p>
              </div>
          ))}
      </div>
  );

  return (
    <div className="flex flex-col min-h-full pb-32 bg-black">

      {/* Search Header */}
      <div className="sticky top-0 bg-[#121212] z-30 pt-3 pb-0 border-b border-white/5 transition-colors duration-300">
         <div className="px-4 flex items-center gap-3 mb-3">
             <button onClick={() => navigate(-1)} className="text-white hover:bg-white/10 p-2 rounded-full transition-colors active:scale-95 md:hidden">
                <ArrowLeft size={24} />
             </button>

             {/* Premium Search Bar */}
             <div className={`flex-1 relative group transition-all duration-300 ease-out ${isFocused ? 'scale-[1.01]' : 'scale-100'}`}>
                <div className={`absolute inset-y-0 left-3.5 flex items-center pointer-events-none transition-colors duration-300 ${isFocused ? 'text-white' : 'text-[#777]'}`}>
                     <SearchIcon size={20} />
                </div>
                <input 
                  type="text"
                  className="w-full bg-[#242424] hover:bg-[#2a2a2a] focus:bg-[#1f1f1f] text-white rounded-full py-3 pl-11 pr-11 outline-none border border-transparent focus:border-white/10 placeholder-[#777] font-medium text-[16px] transition-all"
                  placeholder="What do you want to listen to?"
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  onFocus={() => setIsFocused(true)}
                  onBlur={() => setIsFocused(false)}
                />
                {(query || isLoading) && (
                    <div className="absolute right-3.5 top-1/2 -translate-y-1/2 flex items-center">
                         {isLoading ? <Loader2 size={18} className="text-[#1DB954] animate-spin" /> : <button onClick={clearSearch} className="text-[#777] hover:text-white p-1 rounded-full"><X size={18} /></button>}
                    </div>
                )}
             </div>
         </div>

         {/* Filter Chips - Only show when searching */}
         {query && (
             <div className="flex items-center gap-2 overflow-x-auto no-scrollbar px-4 pb-3">
                 {FILTER_CHIPS.map(chip => (
                     <button
                        key={chip}
                        onClick={() => setActiveFilter(chip)}
                        className={`px-4 py-1.5 rounded-full text-sm font-medium whitespace-nowrap transition-colors border ${activeFilter === chip ? 'bg-[#1DB954] text-black border-[#1DB954]' : 'bg-[#121212] text-white border-white/20 hover:border-white'}`}
                     >
                         {chip}
                     </button>
                 ))}
             </div>
         )}
      </div>

      {/* Results Content */}
      <div className="flex flex-col w-full pb-8 pt-4">
        {isLoading && !results.songs.length ? (
            <div className="flex flex-col w-full pt-2">
                {[1,2,3,4,5].map(i => <ResultSkeleton key={i} />)}
            </div>
        ) : query && (
            <div className="animate-in fade-in slide-in-from-bottom-3 duration-300">
                {/* TOP VIEW (ALL) */}
                {activeFilter === 'Top' && (
                    <div className="flex flex-col gap-6">
                        {results.songs.length > 0 && (
                            <div>
                                <h2 className="text-xl font-bold text-white px-4 mb-3">Songs</h2>
                                <div className="flex flex-col">{renderSongsList(results.songs, 5)}</div>
                            </div>
                        )}
                        {results.artists.length > 0 && (
                            <div>
                                <h2 className="text-xl font-bold text-white px-4 mb-3">Artists</h2>
                                {renderGrid(results.artists.slice(0, 4), 'Artist')}
                            </div>
                        )}
                         {results.albums.length > 0 && (
                            <div>
                                <h2 className="text-xl font-bold text-white px-4 mb-3">Albums</h2>
                                {renderGrid(results.albums.slice(0, 4), 'Album')}
                            </div>
                        )}
                    </div>
                )}

                {/* SONGS ONLY */}
                {activeFilter === 'Songs' && (
                    <div className="flex flex-col">
                        {renderSongsList(results.songs)}
                    </div>
                )}

                {/* ALBUMS ONLY */}
                {activeFilter === 'Albums' && (
                    <div className="pt-2">
                        {renderGrid(results.albums, 'Album')}
                    </div>
                )}

                 {/* ARTISTS ONLY */}
                 {activeFilter === 'Artists' && (
                    <div className="pt-2">
                        {renderGrid(results.artists, 'Artist')}
                    </div>
                )}

                {activeFilter === 'Playlists' && (
                    <div className="flex flex-col items-center justify-center py-20 text-[#777]">
                        <p>No playlists found (Coming soon to Hybrid API)</p>
                    </div>
                )}

                {/* No Results */}
                {results.songs.length === 0 && results.artists.length === 0 && results.albums.length === 0 && (
                    <div className="flex flex-col items-center justify-center pt-20 text-[#777]">
                        <SearchIcon size={40} className="opacity-50 mb-4"/>
                        <h3 className="text-white font-bold text-lg">No results found</h3>
                        <p className="text-sm mt-2">Try searching for a different keyword.</p>
                    </div>
                )}
            </div>
        )}

        {/* Default Browse (No Query) */}
        {!query && (
             <div className="p-4 flex flex-col items-center justify-center text-[#777] min-h-[50vh]">
                 <SearchIcon size={64} className="opacity-20 mb-4" />
                 <p className="font-bold text-white text-xl">Play what you love</p>
                 <p className="text-sm mt-2">Search for artists, songs, podcasts, and more.</p>
             </div>
        )}
      </div>
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, MoreHorizontal, Download, ListMusic, Heart, Loader2, Shuffle, Repeat, PlusCircle, CheckCircle2, Disc, User, Share2, ListPlus, Radio, Mic2, Moon, Info } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { api, getImageUrl, getAudioUrl, getOfflineAudioUrl } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';
import { useNavigate } from 'react-router-dom';

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    setIsPlaying, 
    setIsBuffering,
    nextSong, 
    prevSong,
    likedSongs,
    toggleLike,
    isShuffling,
    streamingQuality,
    isOfflineMode,
    downloadedSongIds,
    addToQueue,
    startDownload
  } = usePlayerStore();

  const navigate = useNavigate();
  const audioRef = useRef<HTMLAudioElement>(null);

  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [dominantColor, setDominantColor] = useState<string>('#121212');
  const [isDragging, setIsDragging] = useState(false);
  const [isMoreMenuOpen, setIsMoreMenuOpen] = useState(false);
  const [isDownloadExpanded, setIsDownloadExpanded] = useState(false);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;
  const isDownloaded = currentSong ? downloadedSongIds.includes(currentSong.id) : false;

  // Extract color
  useEffect(() => {
    if (!currentSong) return;
    const imgUrl = getImageUrl(currentSong.image);
    const img = new Image();
    img.crossOrigin = "Anonymous";
    img.src = imgUrl;
    img.onload = () => {
      try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        canvas.width = 1; canvas.height = 1;
        ctx.drawImage(img, 0, 0, 1, 1);
        const [r, g, b] = ctx.getImageData(0, 0, 1, 1).data;
        setDominantColor(`rgb(${Math.max(20, r - 30)},${Math.max(20, g - 30)},${Math.max(20, b - 30)})`);
      } catch (e) { setDominantColor('#181818'); }
    };
    img.onerror = () => setDominantColor('#181818');
  }, [currentSong?.id]);

  // Media Session
  useEffect(() => {
    if (!currentSong || !('mediaSession' in navigator)) return;
    const hqImage = getImageUrl(currentSong.image);
    navigator.mediaSession.metadata = new MediaMetadata({
      title: currentSong.name,
      artist: currentSong.artists?.primary?.[0]?.name || "Unknown",
      album: currentSong.album?.name || "Single",
      artwork: [{ src: hqImage, sizes: '512x512', type: 'image/jpeg' }]
    });
    navigator.mediaSession.setActionHandler('play', () => setIsPlaying(true));
    navigator.mediaSession.setActionHandler('pause', () => setIsPlaying(false));
    navigator.mediaSession.setActionHandler('previoustrack', prevSong);
    navigator.mediaSession.setActionHandler('nexttrack', nextSong);
  }, [currentSong, setIsPlaying, prevSong, nextSong]);

  // Audio Source Logic (Hybrid Support)
  useEffect(() => {
    if (!currentSong || !audioRef.current) return;

    const setAudioSource = async () => {
        let url = '';

        // 1. Offline Mode / Downloaded
        if (isOfflineMode || downloadedSongIds.includes(currentSong.id)) {
            const blobUrl = await getOfflineAudioUrl(currentSong.id);
            if (blobUrl) url = blobUrl;
            else if (isOfflineMode) { setIsPlaying(false); return; }
        }

        // 2. Online Mode
        if (!url && !isOfflineMode) {
             // Try Saavn downloadUrl first
             if (currentSong.downloadUrl && currentSong.downloadUrl.length > 0) {
                 url = getAudioUrl(currentSong.downloadUrl, streamingQuality);
             } 
             // If no downloadUrl, it's a Hybrid/YT song, fetch stream url
             else {
                 url = await api.getStreamUrl(currentSong.id);
             }
        }

        if (url && audioRef.current && audioRef.current.src !== url) {
            const wasPlaying = isPlaying;
            audioRef.current.src = url;
            audioRef.current.load();
            if (wasPlaying) {
                 audioRef.current.play().catch(() => setIsPlaying(false));
            }
        }
    };
    setAudioSource();
  }, [currentSong?.id, streamingQuality, isOfflineMode]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (isPlaying && audio.paused) audio.play().catch(() => setIsPlaying(false));
    else if (!isPlaying && !audio.paused) audio.pause();
  }, [isPlaying]);

  const handleTimeUpdate = () => {
    if (audioRef.current && !isDragging) {
      setProgress(audioRef.current.currentTime);
      setDuration(audioRef.current.duration || 0);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    setProgress(time);
    if (audioRef.current) audioRef.current.currentTime = time;
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || "Unknown";

  return (
    <>
        <audio 
            ref={audioRef}
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            onEnded={nextSong}
            onWaiting={() => setIsBuffering(true)}
            onPlaying={() => setIsBuffering(false)}
        />

        <AnimatePresence mode="wait">
            {isFullScreen ? (
                <motion.div 
                    initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
                    className="fixed inset-0 z-[200] flex flex-col bg-[#121212] overflow-hidden"
                >
                    <div className="absolute inset-0 z-[-1]" style={{ background: `linear-gradient(to bottom, ${dominantColor}, #121212)` }} />
                    <div className="relative z-10 flex flex-col h-full px-6 pt-safe-top pb-safe-bottom">
                        <div className="flex items-center justify-between h-16 shrink-0 mt-2">
                            <button onClick={() => setFullScreen(false)} className="p-2 -ml-2"><ChevronDown size={28} className="text-white" /></button>
                            <span className="text-xs font-bold uppercase text-white/70 tracking-widest">Now Playing</span>
                            <button onClick={() => setIsMoreMenuOpen(true)} className="p-2 -mr-2"><MoreHorizontal size={24} className="text-white" /></button>
                        </div>
                        <div className="flex-1 flex flex-col justify-center min-h-0 my-4">
                            <div className="relative w-full aspect-square max-w-[340px] mx-auto shadow-2xl rounded-xl overflow-hidden">
                                <img src={imageUrl} alt="Cover" className="w-full h-full object-cover" />
                            </div>
                        </div>
                        <div className="flex flex-col gap-6 mb-10">
                            <div className="flex items-center justify-between">
                                <div className="flex flex-col overflow-hidden mr-4">
                                    <h2 className="text-2xl font-bold text-white truncate">{currentSong.name}</h2>
                                    <p className="text-lg text-white/70 truncate">{primaryArtistName}</p>
                                </div>
                                <button onClick={() => toggleLike(currentSong)}><CheckCircle2 size={28} className={isLiked ? "text-[#1DB954]" : "text-white/70"} /></button>
                            </div>
                            <div className="flex flex-col gap-2">
                                <input 
                                    type="range" min="0" max={duration || 100} value={progress}
                                    onChange={handleSeek}
                                    className="w-full h-1 bg-white/20 rounded-lg appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-3 [&::-webkit-slider-thumb]:h-3 [&::-webkit-slider-thumb]:bg-white [&::-webkit-slider-thumb]:rounded-full"
                                />
                                <div className="flex justify-between text-xs text-white/50 font-medium">
                                    <span>{Math.floor(progress / 60)}:{(Math.floor(progress) % 60).toString().padStart(2, '0')}</span>
                                    <span>{Math.floor(duration / 60)}:{(Math.floor(duration) % 60).toString().padStart(2, '0')}</span>
                                </div>
                            </div>
                            <div className="flex items-center justify-between px-2">
                                <button className="text-white/40"><Shuffle size={20} /></button>
                                <button onClick={prevSong}><SkipBack size={32} className="text-white" fill="white" /></button>
                                <button onClick={togglePlay} className="w-16 h-16 bg-white rounded-full flex items-center justify-center">
                                    {isBuffering ? <Loader2 size={32} className="animate-spin text-black" /> : isPlaying ? <Pause size={32} fill="black" className="text-black" /> : <Play size={32} fill="black" className="ml-1 text-black" />}
                                </button>
                                <button onClick={nextSong}><SkipForward size={32} className="text-white" fill="white" /></button>
                                <button className="text-white/40"><Repeat size={20} /></button>
                            </div>
                        </div>
                    </div>
                </motion.div>
            ) : (
                <motion.div 
                    initial={{ y: 50, opacity: 0 }} animate={{ y: 0, opacity: 1 }} exit={{ y: 50, opacity: 0 }}
                    className="fixed bottom-[68px] md:bottom-4 left-2 right-2 md:left-1/2 md:-translate-x-1/2 md:w-[450px] h-[56px] z-[150] cursor-pointer"
                    onClick={() => setFullScreen(true)}
                >
                    <div className="absolute inset-0 z-[-1] rounded-lg shadow-xl overflow-hidden" style={{ backgroundColor: dominantColor }}>
                         <div className="absolute inset-0 bg-black/20" />
                    </div>
                    <div className="flex items-center h-full px-2 gap-3">
                        <img src={imageUrl} alt="" className="h-10 w-10 rounded-[4px] object-cover" />
                        <div className="flex-1 flex flex-col justify-center min-w-0 pr-2">
                            <span className="text-white font-bold text-xs truncate">{currentSong.name}</span>
                            <span className="text-white/70 text-[10px] truncate">{primaryArtistName}</span>
                        </div>
                        <button onClick={(e) => { e.stopPropagation(); toggleLike(currentSong); }} className="p-1.5"><Heart size={20} className={isLiked ? "text-[#1DB954] fill-[#1DB954]" : "text-white"} /></button>
                        <button onClick={(e) => { e.stopPropagation(); togglePlay(); }} className="p-1.5">
                            {isBuffering ? <Loader2 size={24} className="animate-spin text-white" /> : isPlaying ? <Pause size={24} fill="white" className="text-white" /> : <Play size={24} fill="white" className="text-white" />}
                        </button>
                    </div>
                    <div className="absolute bottom-0 left-1 right-1 h-[2px] bg-white/20 rounded-full overflow-hidden">
                        <div className="h-full bg-white rounded-full" style={{ width: `${(progress / (duration || 1)) * 100}%` }}></div>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
    </>
  );
};
